import scala.xml.XML

trait ConfigParser {

  def parseConfig(xml: String): Map[String, String] = {
    val config = XML.loadString(xml)
    config.child.map { node =>
      node.label -> node.text
    }.toMap
  }

  def extractEntity(xml: String): Map[String, String] = {
    val config = XML.loadString(xml)
    val entities = config.xpath("//entity").map { node =>
      val name = node.attribute("name").get.text
      val value = node.text
      name -> value
    }
    entities.toMap
  }

  def parseEntityRef(xml: String, entities: Map[String, String]): Map[String, String] = {
    val config = XML.loadString(xml)
    config.child.map { node =>
      val key = node.label
      val value = entities.getOrElse(node.text, "")
      key -> value
    }.toMap
  }
}